n            },\n            {\n                \"id\": \"fdoc_002\",\n                \"es_valido\": true,\n                \"horas\": 2,\n                \"rol\": \"asistente\",\n                \"relacion_docente\": true,\n                \"fuente_texto\": \"TITULO\\n\\nUso profesional de la voz\\n\\nOBJETIVOS\\n\\nConceptos básicos: conociendo el aparato fonador Funcionamiento de\\nla voz Uso profesional de la voz Pautas genéricas de cuidado vocal\\nBuenas prácticas en el uso de la voz proyectada\\n\\nPERFIL\\n\\nPersonal investigador y docente de la Universidad de Granada\\n\\nFDESDE\\n\\n2022-10-19\\n\\nFHASTA\\n\\n2022-10-19\\n\\nHORAS\\n\\n2\\n\\nENTIDAD\\n\\nFREMAP, Mutua Colaboradora con la Seguridad Social nº61\\n\\nLUGAR\\n\\nOnline\\n\\nFECHA\\n\\n2022-10-19\",\n                \"confianza_extraccion\": 0.9,\n                \"requiere_revision\": true\n            },\n            {\n                \"id\": \"fdoc_003\",\n                \"es_valido\": true,\n                \"horas\": 1,\n                \"rol\": \"asistente\",\n                \"relacion_docente\": true,\n                \"fuente_texto\": \"TITULO\\n\\nEQUIPOS DE EMERGENCIA UF3\\n\\nOBJETIVOS\\n\\nFormación de equipos de emergencia en una universidad Fernando\\nIII implica preparar y organizar a un grupo de personas (personal\\nadministrativo, docente y personal de mantenimiento) para responder\\nde manera eficiente y coordinada a emergencias que puedan ocurrir\\nen el campus. Este proceso debe adaptarse a las características y\\nparticularidades de un entorno universitario, como la alta afluencia de\\npersonas, los horarios diversos y la gran cantidad de espacios físicos.\\n\\nPERFIL\\n\\nPersonal Docente e Investigador\\n\\nFDESDE\\n\\n2024-12-16\\n\\n24\\n\\n\\fFHASTA\\n\\n2024-12-16\\n\\nHORAS\\n\\n1\\n\\nENTIDAD\\n\\nUniversidad CEU Fernando III\\n\\nFECHA\\n\\n2024-12-16\",\n                \"confianza_extraccion\": 0.9,\n                \"requiere_revision\": true\n            